package org.eclipse.rdf4j.query.algebra.evaluation.impl;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.QueryModelNode;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.parser.ParsedTupleQuery;
import org.eclipse.rdf4j.query.parser.QueryParserUtil;
import org.junit.jupiter.api.Test;

class ArrayBindingBasedQueryEvaluationContextTest {

	@Test
	void findAllVariablesUsedInQueryPreservesValuesVariableOrder() {
		ParsedTupleQuery parsedQuery = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, """
				PREFIX social: <http://example.com/theme/social/>
				SELECT (COUNT(DISTINCT ?pair) AS ?count) WHERE {
				  VALUES (?u ?v) {
				    (<http://example.com/theme/social/user/0> <http://example.com/theme/social/user/0>)
				    (<http://example.com/theme/social/user/0> <http://example.com/theme/social/user/1>)
				  }
				  FILTER (?u != ?v)
				  ?u social:follows ?v .
				  OPTIONAL {
				    ?u social:name ?optName .
				  }
				  FILTER (?optName IN ("user0", "user1", "user2"))
				  BIND(CONCAT(STR(?u), STR(?v)) AS ?pair)
				}
				""", null);

		QueryRoot root = (QueryRoot) parsedQuery.getTupleExpr();
		BindingSetAssignment before = findFirst(root, BindingSetAssignment.class);
		assertEquals(List.of("u", "v"), new ArrayList<>(before.getBindingNames()));

		ArrayBindingBasedQueryEvaluationContext.findAllVariablesUsedInQuery(root);

		BindingSetAssignment after = findFirst(root, BindingSetAssignment.class);
		assertEquals(List.of("u", "v"), new ArrayList<>(after.getBindingNames()));
	}

	private static <T extends QueryModelNode> T findFirst(QueryModelNode root, Class<T> type) {
		List<T> matches = new ArrayList<>(1);
		root.visit(new org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) throws RuntimeException {
				if (matches.isEmpty() && type.isInstance(node)) {
					matches.add(type.cast(node));
				}
				super.meetNode(node);
			}
		});

		if (matches.isEmpty()) {
			throw new AssertionError("Expected to find node of type " + type.getSimpleName());
		}

		return matches.get(0);
	}
}
